const wh = $('Webhook Trigger1').first();
if (!wh || !wh.binary || !Object.keys(wh.binary).length) {
  throw new Error('Nenhum arquivo enviado. Envie um CSV ou XLS/XLSX.');
}
const item = $input.first();
item.binary = wh.binary;
return [item];

const bin = $input.first().binary || {};
const binProp = bin.file ? 'file' : Object.keys(bin)[0];
if (!binProp) throw new Error('Nenhum arquivo binário encontrado no webhook.');
const buf = await this.helpers.getBinaryDataBuffer(0, binProp);

let text = buf.toString('utf8');
if (((text.match(/\uFFFD/g) || []).length) > 3) text = buf.toString('latin1');
text = text.replace(/^\uFEFF/, '');

const lines = text.split(/\r?\n/).filter((l) => l.trim().length);
if (!lines.length) throw new Error('Arquivo vazio. Envie um CSV/XLS com dados.');

const sniff = lines.slice(0, 8).join('\n');
const delim = ((sniff.split(';').length) >= (sniff.split(',').length)) ? ';' : ',';

function parseLine(line) {
  const out = []; let cur = ''; let q = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (q) {
      if (ch === '"') { if (line[i + 1] === '"') { cur += '"'; i++; } else q = false; }
      else cur += ch;
    } else {
      if (ch === '"') q = true;
      else if (ch === delim) { out.push(cur); cur = ''; }
      else cur += ch;
    }
  }
  out.push(cur);
  return out.map((s) => s.trim());
}

const header = parseLine(lines[0]).map(h => h.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim());

const REQUIRED_COLS = ['id_item'];
const VALID_COLS = ['id_item','descricao','tipo_mercado','familia_totvs','familia_comercial','familia_plan_i','familia_plan_ii','curva_abc_est','curva_abc_vendas','numero'];

const COL_ALIASES = {
  'codigo':'id_item','cod':'id_item','cod_item':'id_item','id':'id_item','idproduto':'id_item','id_produto':'id_item',
  'nome':'descricao','desc':'descricao','produto':'descricao',
  'tipo':'tipo_mercado','mercado':'tipo_mercado',
  'familia':'familia_totvs','familiatotvs':'familia_totvs','familiacomercial':'familia_comercial',
  'familiaplani':'familia_plan_i','familiaplan1':'familia_plan_i',
  'familiaplanii':'familia_plan_ii','familiaplan2':'familia_plan_ii',
  'curva_estoque':'curva_abc_est','curva_vendas':'curva_abc_vendas',
  'num':'numero','numeroitem':'numero'
};

function mapColName(raw) {
  const clean = raw.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9_]/g, '');
  if (VALID_COLS.includes(clean)) return clean;
  if (COL_ALIASES[clean]) return COL_ALIASES[clean];
  const match = VALID_COLS.find(c => clean.includes(c) || c.includes(clean));
  if (match) return match;
  return clean;
}

const mappedHeader = header.map(mapColName);

const missingRequired = REQUIRED_COLS.filter(c => !mappedHeader.includes(c));
if (missingRequired.length > 0) {
  throw new Error(`Formato inválido. Coluna obrigatória não encontrada: ${missingRequired.join(', ')}. Colunas aceitas: ${VALID_COLS.join(', ')}`);
}

const rows = [];
for (let i = 1; i < lines.length; i++) {
  const cells = parseLine(lines[i]);
  if (cells.every((c) => c === '')) continue;
  const o = {};
  mappedHeader.forEach((key, idx) => {
    if (VALID_COLS.includes(key)) o[key] = cells[idx] !== undefined ? cells[idx] : null;
  });
  for (const [k, v] of Object.entries(o)) { if (v === '' || v === undefined) o[k] = null; }
  if (o.numero !== null && o.numero !== undefined) {
    const n = parseInt(String(o.numero).replace(/[^0-9-]/g, ''), 10);
    o.numero = Number.isNaN(n) ? null : n;
  }
  for (const campo of ['curva_abc_est','curva_abc_vendas']) {
    if (o[campo]) {
      o[campo] = String(o[campo]).trim().toUpperCase().charAt(0);
      if (!['A','B','C'].includes(o[campo])) o[campo] = null;
    }
  }
  if (o.id_item && String(o.id_item).trim() !== '') rows.push({ json: o });
}

if (rows.length === 0) throw new Error('Nenhuma linha válida encontrada. Verifique a coluna id_item.');
return rows;
